import React from 'react';
import { useParams, Link } from 'react-router-dom';
import { todasNoticias } from '../data/noticiasDestaques';

const categoriaBadgeClass = {
  Lançamento: 'bg-success',
  Eventos: 'bg-primary',
  Imprensa: 'bg-secondary',
  Prêmios: 'bg-warning text-dark',
  Música: 'bg-info text-dark',
  Charts: 'bg-dark'
};

function NoticiaDetalhe() {
  const { id } = useParams();
  const noticia = todasNoticias.find((n) => String(n.id) === String(id));

  if (!noticia) {
    return (
      <div className="container py-5 text-center">
        <h1>Notícia não encontrada</h1>
        <p className="text-muted">A notícia que você procura não existe.</p>
        <Link to="/noticias" className="btn btn-success">
          Voltar para notícias
        </Link>
      </div>
    );
  }

  const paragrafos = noticia.conteudo.split('\n\n').filter((p) => p.trim());

  return (
    <div className="container py-5">
      <Link to="/noticias" className="btn btn-outline-secondary mb-4">
        ← Voltar para notícias
      </Link>

      <article>
        <header className="mb-4">
          <span
            className={`badge mb-2 ${categoriaBadgeClass[noticia.categoria] || 'bg-secondary'}`}
          >
            {noticia.categoria}
          </span>
          <h1 className="mb-3">{noticia.titulo}</h1>
          <p className="text-muted mb-1">
            <strong>Data:</strong> {noticia.data}
          </p>
          <p className="text-muted mb-0">
            <strong>Fonte original:</strong>{' '}
            <a href={noticia.link} target="_blank" rel="noopener noreferrer">
              {noticia.fonte}
            </a>
          </p>
        </header>

        <div className="article-content mb-4">
          <p className="lead text-muted">{noticia.resumo}</p>
          {paragrafos.map((paragrafo, index) => (
            <p key={index}>{paragrafo.trim()}</p>
          ))}
        </div>

        <div className="d-flex flex-wrap gap-2 mb-5">
          <a href={noticia.link} target="_blank" rel="noopener noreferrer" className="btn btn-success">
            Abrir matéria completa na fonte ↗
          </a>
        </div>
      </article>

      <section className="pt-4 border-top">
        <h3 className="h5 mb-3">Outras notícias</h3>
        <div className="row g-3">
          {todasNoticias
            .filter((n) => n.id !== noticia.id)
            .slice(0, 3)
            .map((n) => (
              <div key={n.id} className="col-md-4">
                <div className="card h-100 shadow-sm">
                  <div className="card-body">
                    <h6 className="card-title small">{n.titulo}</h6>
                    <p className="card-text small text-muted mb-2">{n.data}</p>
                    <Link to={`/noticias/${n.id}`} className="btn btn-sm btn-outline-success">
                      Ler
                    </Link>
                  </div>
                </div>
              </div>
            ))}
        </div>
      </section>
    </div>
  );
}

export default NoticiaDetalhe;
